// ─── Decorative Frames ────────────────────────────

export const FRAMES = {
    simple: (text) => {
        const lines = text.split('\n');
        const maxLen = Math.max(...lines.map(l => l.length));
        const top = '  ╭' + '─'.repeat(maxLen + 2) + '╮';
        const bot = '  ╰' + '─'.repeat(maxLen + 2) + '╯';
        const body = lines.map(l => '  │ ' + l.padEnd(maxLen) + ' │');
        return [top, ...body, bot].join('\n');
    },
    double: (text) => {
        const lines = text.split('\n');
        const maxLen = Math.max(...lines.map(l => l.length));
        const top = '  ╔' + '═'.repeat(maxLen + 2) + '╗';
        const bot = '  ╚' + '═'.repeat(maxLen + 2) + '╝';
        const body = lines.map(l => '  ║ ' + l.padEnd(maxLen) + ' ║');
        return [top, ...body, bot].join('\n');
    },
    stars: (text) => {
        const lines = text.split('\n');
        const maxLen = Math.max(...lines.map(l => l.length));
        const border = '  ✦' + '═'.repeat(maxLen + 2) + '✦';
        const body = lines.map(l => '  ║ ' + l.padEnd(maxLen) + ' ║');
        return [border, ...body, border].join('\n');
    },
};

// ─── Utility: Render with Color ───────────────────

export function renderAscii(art, color = '#4ECDC4') {
    if (Array.isArray(art)) {
        return art.map(line => chalk.hex(color)(line)).join('\n');
    }
    return chalk.hex(color)(art);
}

export function renderGradientAscii(art, colors = ['#6C63FF', '#E040FB', '#FF4081']) {
    const grad = gradient(colors);
    if (Array.isArray(art)) {
        return art.map(line => grad(line)).join('\n');
    }
    return grad(art);
}

// ─── Utility: Show Header ─────────────────────────

export function showHeader(name, color = '#4ECDC4') {
    const header = HEADERS[name];
    if (header) {
        console.log(renderAscii(header, color));
    }
}

// ─── Utility: Show Mood Face ──────────────────────

export function showMoodFace(mood, color) {
    const face = MOOD_FACES[mood] || MOOD_FACES.okay;
    const c = color || '#4ECDC4';
    console.log(renderAscii(face, c));
}

